def validate(args, output):
    pairs = args[0]
    if not isinstance(output, list) or len(output) != len(pairs):
        return False
    from collections import Counter
    given = Counter(tuple(p) for p in pairs)
    used = Counter()
    for p in output:
        if not isinstance(p, list) or len(p) != 2:
            return False
        used[(p[0], p[1])] += 1
    if used != given:
        return False
    for i in range(1, len(output)):
        if output[i - 1][1] != output[i][0]:
            return False
    return True

