function validate(args, output) {
    const pairs = args[0];
    if (!Array.isArray(output) || output.length !== pairs.length) return false;
    const key = (a, b) => a + ',' + b;
    const given = new Map();
    for (const [a, b] of pairs) {
        const k = key(a, b);
        given.set(k, (given.get(k) || 0) + 1);
    }
    const used = new Map();
    for (const p of output) {
        if (!Array.isArray(p) || p.length !== 2) return false;
        const k = key(p[0], p[1]);
        used.set(k, (used.get(k) || 0) + 1);
    }
    if (given.size !== used.size) return false;
    for (const [k, v] of given) {
        if (used.get(k) !== v) return false;
    }
    for (let i = 1; i < output.length; i++) {
        if (output[i - 1][1] !== output[i][0]) return false;
    }
    return true;
}

