var validArrangement = function(pairs) {
    const graph = new Map();
    const outdeg = new Map();
    const indeg = new Map();
    for (const [u, v] of pairs) {
        if (!graph.has(u)) graph.set(u, []);
        graph.get(u).push(v);
        outdeg.set(u, (outdeg.get(u) || 0) + 1);
        indeg.set(v, (indeg.get(v) || 0) + 1);
    }

    let start = pairs[0][0];
    for (const u of outdeg.keys()) {
        const od = outdeg.get(u) || 0;
        const id = indeg.get(u) || 0;
        if (od - id === 1) {
            start = u;
            break;
        }
    }

    const ptr = new Map();
    const stack = [start];
    const path = [];
    while (stack.length) {
        const node = stack[stack.length - 1];
        const adj = graph.get(node) || [];
        const p = ptr.get(node) || 0;
        if (p < adj.length) {
            ptr.set(node, p + 1);
            stack.push(adj[p]);
        } else {
            path.push(stack.pop());
        }
    }
    path.reverse();
    const res = [];
    for (let i = 0; i < path.length - 1; i++) res.push([path[i], path[i + 1]]);
    return res;
};
